// newTestClientWithGraphQLMock creates a test client with a mock GraphQL client injected
func newTestClientWithGraphQLMock(t testing.TB, mockGraphQLClient *MockGraphqlClient) *Client {
	t.Helper()

	rcache.SetupForTest(t)
	redispool.SetupForTest(t, tenanttest.TestContext())

	baseURL, err := url.Parse("https://gitlab.com/")
	require.NoError(t, err)

	provider := NewClientProvider("TestMock", baseURL, nil)
	cli := provider.GetOAuthClient("")
	cli.internalRateLimiter = ratelimit.NewInstrumentedLimiter("gitlab", rate.NewLimiter(100, 10))

	// Inject the mock GraphQL client
	cli.graphqlClientSource = func(url string, doer httpcli.Doer) graphqlClient {
		return mockGraphQLClient
	}

	return cli
}

func newTestVCRClientForGroups(t testing.TB, name string) (*Client, func()) {
	t.Helper()

	rcache.SetupForTest(t)
	redispool.SetupForTest(t, tenanttest.TestContext())

	cf, save := httptestutil.NewRecorderFactory(t, update(name), name)
	doer, err := cf.Doer()
	if err != nil {
		t.Fatal(err)
	}

	baseURL, err := url.Parse("https://gitlab.com/")
	if err != nil {
		t.Fatal(err)
	}

	provider := NewClientProvider("TestVCR", baseURL, doer)

	// Try to use a token if available for VCR recording, otherwise use unauthenticated
	token := ""
	if vcrToken != nil && vcrToken.Token != "" {
		token = vcrToken.Token
	}

	cli := provider.GetOAuthClient(token)
	cli.internalRateLimiter = ratelimit.NewInstrumentedLimiter("gitlab", rate.NewLimiter(100, 10))

	return cli, save
}

func TestIsNumericID(t *testing.T) {
	t.Run("numeric strings", func(t *testing.T) {
		if !isNumericID("123") {
			t.Error("Expected isNumericID to return true for '123'")
		}
	})

	t.Run("global ids", func(t *testing.T) {
		if isNumericID("gid://gitlab/Group/123") {
			t.Error("Expected isNumericID to return false for Global ID")
		}
	})

	t.Run("non-numeric strings", func(t *testing.T) {
		if isNumericID("abc") {
			t.Error("Expected isNumericID to return false for 'abc'")
		}
	})
}

// TestClient_GetGroupsByIDs_VCR tests the GetGroupsByIDs method using VCR recordings.
// This test uses hardcoded group IDs that are known to exist in GitLab.com.
func TestClient_GetGroupsByIDs_VCR(t *testing.T) {
	cli, save := newTestVCRClientForGroups(t, "GetGroupsByIDs")
	defer save()

	ctx := tenanttest.TestContext()

	// Test group IDs discovered from GitLab.com API
	// These are real groups created for testing purposes by the sourcegraph-vcr user
	const (
		testGroupID1 = "108328765" // sourcegraph-vcr-real-group
		testGroupID2 = "108329154" // sourcegraph-vcr-real-group-2

		// GraphQL Global IDs for the same groups
		testGroupGlobalID1 = "gid://gitlab/Group/108328765"
		testGroupGlobalID2 = "gid://gitlab/Group/108329154"
	)

	t.Run("single-numeric-id", func(t *testing.T) {
		groups, err := cli.GetGroupsByIDs(ctx, []string{testGroupID1})
		if err != nil {
			t.Fatal(err)
		}

		testutil.AssertGolden(t,
			"testdata/golden/GetGroupsByIDs-VCR-single-numeric-id",
			update("GetGroupsByIDs"),
			map[string]any{
				"groups": groups,
			},
		)

		// Verify we got exactly one group
		if len(groups) != 1 {
			t.Errorf("Expected 1 group, got %d", len(groups))
		}

		if len(groups) > 0 {
			// Verify the group has expected basic properties
			group := groups[0]
			if group.ID != 108328765 {
				t.Errorf("Expected group ID 108328765, got %d", group.ID)
