func TestClient_GetGroupsByIDs_EdgeCases(t *testing.T) {
	ctx := tenanttest.TestContext()

	t.Run("empty response handling", func(t *testing.T) {
		t.Cleanup(func() {
			MockGetGroupsByIDs = nil
		})
		MockGetGroupsByIDs = func(c *Client, ctx context.Context, ids []string) ([]*Group, error) {
			return []*Group{}, nil
		}

		c := newTestClient(t)
		groups, err := c.GetGroupsByIDs(ctx, []string{"999"})
		if err != nil {
			t.Fatal(err)
		}

		if len(groups) != 0 {
			t.Errorf("Expected 0 groups for empty response, got %d", len(groups))
		}
	})

	t.Run("error handling", func(t *testing.T) {
		t.Cleanup(func() {
			MockGetGroupsByIDs = nil
		})
		MockGetGroupsByIDs = func(c *Client, ctx context.Context, ids []string) ([]*Group, error) {
			return nil, errors.Wrapf(assert.AnError, "test error")
		}

		c := newTestClient(t)
		_, err := c.GetGroupsByIDs(ctx, []string{"1"})
		require.ErrorIs(t, err, assert.AnError)
	})

	t.Run("pagination", func(t *testing.T) {
		ctx := tenanttest.TestContext()

		createTestGroup := func(id string, name string) *gql.GroupConnectionFieldsNodesGroup {
			return &gql.GroupConnectionFieldsNodesGroup{
				GroupFields: gql.GroupFields{
					Id:          id,
					Name:        name,
					FullPath:    name,
					Description: "Test group",
					WebUrl:      "https://gitlab.com/" + name,
					AvatarUrl:   "",
					Visibility:  "private",
				},
			}
		}

		t.Run("single page response", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// Setup single page response
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/1", "group1"),
							*createTestGroup("gid://gitlab/Group/2", "group2"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: false,
								EndCursor:   "cursor1",
							},
						},
						Count: 2,
					},
				},
			}, nil)

			c := newTestClientWithGraphQLMock(t, mockClient)
			groups, err := c.GetGroupsByIDs(ctx, []string{"1", "2"})
			require.NoError(t, err)
			require.Len(t, groups, 2)

			// Verify only one GraphQL call was made
			calls := mockClient.GetGroupsByIDsFunc.History()
			require.Len(t, calls, 1)

			// Verify the call parameters
			call := calls[0]
			require.Equal(t, []string{"gid://gitlab/Group/1", "gid://gitlab/Group/2"}, call.Arg1)
			require.Equal(t, 50, call.Arg2)
			require.Equal(t, "", call.Arg3) // No cursor for first page
		})

		t.Run("multi page response", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// First page
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/1", "group1"),
							*createTestGroup("gid://gitlab/Group/2", "group2"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: true,
								EndCursor:   "cursor1",
							},
						},
						Count: 4,
					},
				},
			}, nil)

			// Second page
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/3", "group3"),
							*createTestGroup("gid://gitlab/Group/4", "group4"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: false,
								EndCursor:   "cursor2",
							},
						},
						Count: 4,
					},
				},
			}, nil)

			c := newTestClientWithGraphQLMock(t, mockClient)
			groups, err := c.GetGroupsByIDs(ctx, []string{"1", "2", "3", "4"})
			require.NoError(t, err)
			require.Len(t, groups, 4)

			// Verify correct number of GraphQL calls
			calls := mockClient.GetGroupsByIDsFunc.History()
			require.Len(t, calls, 2)

			// Verify first call parameters
			call1 := calls[0]
			require.Equal(t, []string{"gid://gitlab/Group/1", "gid://gitlab/Group/2", "gid://gitlab/Group/3", "gid://gitlab/Group/4"}, call1.Arg1)
			require.Equal(t, 50, call1.Arg2)
			require.Equal(t, "", call1.Arg3) // No cursor for first page

			// Verify second call parameters
			call2 := calls[1]
			require.Equal(t, []string{"gid://gitlab/Group/1", "gid://gitlab/Group/2", "gid://gitlab/Group/3", "gid://gitlab/Group/4"}, call2.Arg1)
			require.Equal(t, 50, call2.Arg2)
			require.Equal(t, "cursor1", call2.Arg3) // Cursor from first page
		})

		t.Run("empty cursor protection", func(t *testing.T) {
