// verifyUserGroups checks whether the authenticated user belongs to one of the GitLab groups when the allowGroups option is set.
// It uses targeted API calls for each configured group path instead of paginating all user groups, which avoids rate limiting for users with many group memberships.
func (s *sessionIssuerHelper) verifyUserGroups(ctx context.Context, glClient *gitlab.Client) (bool, error) {
	if len(s.allowGroups) == 0 {
		return true, nil
	}

	for _, groupPath := range s.allowGroups {
		_, err := glClient.GetGroupByPath(ctx, groupPath)
		if err != nil {
			if gitlab.IsNotFound(err) {
				continue
			}
			return false, err
		}
		return true, nil
	}

	return false, nil
}

